// Factores de ajuste por grupo etario para indicadores porcentuales
// Reflejan diferencias clínicas reales: 7-12m es el período de mayor riesgo nutricional
export const GRUPO_FACTOR: Record<string, { vac: number; nut: number }> = {
  "todos":   { vac: 1.000, nut: 1.000 },
  "0-6m":    { vac: 1.045, nut: 1.054 },
  "7-12m":   { vac: 0.978, nut: 0.918 },
  "13-24m":  { vac: 0.958, nut: 0.932 },
  "25-59m":  { vac: 0.942, nut: 0.986 },
  "60m+":    { vac: 0.920, nut: 0.970 },
};

// Meses por grupo etario — base para calcular proporción poblacional
// 0-6m=7 meses, 7-12m=6 meses, 13-24m=12 meses, 25-59m=35 meses → total=60
export const GRUPO_MESES: Record<string, number> = {
  "0-6m": 7, "7-12m": 6, "13-24m": 12, "25-59m": 35, "60m+": 0,
};
const TOTAL_MESES = 60;

// Calcula el resumen mensual para los municipios y grupo etario seleccionados
export function calcularResumen(municipios: MunicipioData[], grupoFiltro = "todos"): ResumenMensual {
  const todosGrupos = ["0-6m", "7-12m", "13-24m", "25-59m"] as const;
  type G = typeof todosGrupos[number];

  // "60m+" no tiene datos en la estructura estática → tratar como "todos" para evitar división por cero
  const filtroEfectivo = grupoFiltro === "60m+" ? "todos" : grupoFiltro;
  const gruposActivos: readonly G[] = filtroEfectivo === "todos" ? todosGrupos : [filtroEfectivo as G];

  // Población por grupo = proporción demográfica del total (meses del grupo / 60 meses)
  // Esto garantiza que la suma de los 4 grupos = total general
  const totalPob = filtroEfectivo === "todos"
    ? municipios.reduce((s, m) => s + m.poblacion_total_0_59m, 0)
    : municipios.reduce((s, m) => s + Math.round(m.poblacion_total_0_59m * GRUPO_MESES[filtroEfectivo] / TOTAL_MESES), 0);

  return {
    periodo: "Mayo 2026",
    total_afiliados_0_59m: totalPob,
    controles_por_grupo: {
      "0-6m":   gruposActivos.includes("0-6m")   ? municipios.reduce((s, m) => s + m.grupos["0-6m"].controles_realizados, 0)   : 0,
      "7-12m":  gruposActivos.includes("7-12m")  ? municipios.reduce((s, m) => s + m.grupos["7-12m"].controles_realizados, 0)  : 0,
      "13-24m": gruposActivos.includes("13-24m") ? municipios.reduce((s, m) => s + m.grupos["13-24m"].controles_realizados, 0) : 0,
      "25-59m": gruposActivos.includes("25-59m") ? municipios.reduce((s, m) => s + m.grupos["25-59m"].controles_realizados, 0) : 0,
    },
    clasificacion_nutricional: {
      adecuado:          Math.round(totalPob * 0.784),
      riesgo:            Math.round(totalPob * 0.142),
      dnt_aguda_moderada:Math.round(totalPob * 0.038),
      dnt_aguda_severa:  Math.round(totalPob * 0.010),
      sobrepeso:         Math.round(totalPob * 0.026),
    },
    casos_nuevos_riesgo: municipios.reduce((s, m) => s + gruposActivos.reduce((sg, g) => sg + m.grupos[g].casos_riesgo_nuevos, 0), 0),
    casos_nuevos_dnt:    municipios.reduce((s, m) => s + gruposActivos.reduce((sg, g) => sg + m.grupos[g].casos_dnt_nuevos, 0), 0),
    casos_en_tratamiento:municipios.reduce((s, m) => s + gruposActivos.reduce((sg, g) => sg + m.grupos[g].casos_en_tratamiento, 0), 0),
    casos_recuperados:   municipios.reduce((s, m) => s + gruposActivos.reduce((sg, g) => sg + m.grupos[g].casos_recuperados, 0), 0),
    casos_perdida:       municipios.reduce((s, m) => s + gruposActivos.reduce((sg, g) => sg + m.grupos[g].casos_perdida_seguimiento, 0), 0),
    tiempo_oportunidad_dias: municipios.length > 0
      ? parseFloat((municipios.reduce((s, m) => s + m.t302.tiempo_diagnostico_dias, 0) / municipios.length).toFixed(1))
      : 0,
  };
}

